parameters.functionCode:
const alert = $input.first().json;

// Classification logic
let severity = 'LOW';
if (alert.severityScore > 80) severity = 'CRITICAL';
else if (alert.severityScore > 60) severity = 'HIGH';
else if (alert.severityScore > 40) severity = 'MEDIUM';

// Check for known false positives
const knownFPs = ['internal_scan', 'test_alert', 'maintenance_window'];
const isLikelyFP = knownFPs.some(fp => alert.description?.toLowerCase().includes(fp));

return { ...alert, severity, isLikelyFP, needsInvestigation: severity !== 'LOW' && !isLikelyFP };

const alert = $input.all()[0].json;
const threatIntel = $input.all()[1].json;

// Check for related alerts in last hour
const relatedAlerts = threatIntel.related || [];
const correlationScore = relatedAlerts.length > 2 ? 'HIGH' : relatedAlerts.length > 0 ? 'MEDIUM' : 'LOW';

return { ...alert, correlationScore, relatedCount: relatedAlerts.length };

